if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const rows = $input.all();
const now = new Date();
let cached = null;
let isFresh = false;
let ageMinutes = null;

if (rows.length > 0 && rows[0].json && rows[0].json.data) {
  cached = rows[0].json.data;
  const createdAt = new Date(rows[0].json.created_at);
  ageMinutes = Math.round((now - createdAt) / 60000);
  isFresh = ageMinutes < 30;
}

if (cached) {
  const response = typeof cached === 'string' ? JSON.parse(cached) : cached;
  response._cache_meta = {
    served_from: 'cache',
    cache_age_minutes: ageMinutes,
    is_fresh: isFresh,
    refreshing: !isFresh,
    served_at: now.toISOString()
  };
  return [{ json: response }];
} else {
  return [{ json: {
    top_clients: [],
    agency_programs: [],
    generated_at: now.toISOString(),
    _cache_meta: {
      served_from: 'empty',
      cache_age_minutes: null,
      is_fresh: false,
      refreshing: true,
      served_at: now.toISOString(),
      message: 'First run - data is being generated. Please retry in ~90 seconds.'
    }
  }}];
}
